SELECT p.id, p.name_cn, p.name_en, p.scope, p.resource_type, p.resource_id, p.category_id, p.need_approval, p.resource_nodes, p.status, p.create_time, p.last_update_time, p.create_by, p.last_update_by FROM openplatform_v2_permission_t p WHERE p.resource_type = 'api'
AND EXISTS ( SELECT 1 FROM openplatform_v2_category_t c WHERE c.id = p.category_id AND c.path LIKE CONCAT(#{categoryPath}, '%') )
AND p.category_id = #{categoryId}
AND (p.name_cn LIKE CONCAT('%', #{keyword}, '%') OR p.name_en LIKE CONCAT('%', #{keyword}, '%') OR p.scope LIKE CONCAT('%', #{keyword}, '%'))
AND EXISTS ( SELECT 1 FROM openplatform_v2_permission_p_t pp WHERE pp.parent_id = p.id AND pp.property_name = 'need_approval' AND pp.property_value = #{needApproval} )
ORDER BY p.create_time DESC LIMIT #{offset}, #{pageSize}

SELECT p.id, p.name_cn, p.name_en, p.scope, p.resource_type, p.resource_id, p.category_id, p.need_approval, p.resource_nodes, p.status, p.create_time, p.last_update_time, p.create_by, p.last_update_by FROM openplatform_v2_permission_t p WHERE p.resource_type = 'event'
AND EXISTS ( SELECT 1 FROM openplatform_v2_category_t c WHERE c.id = p.category_id AND c.path LIKE CONCAT(#{categoryPath}, '%') )
AND p.category_id = #{categoryId}
AND (p.name_cn LIKE CONCAT('%', #{keyword}, '%') OR p.name_en LIKE CONCAT('%', #{keyword}, '%') OR p.scope LIKE CONCAT('%', #{keyword}, '%'))
AND EXISTS ( SELECT 1 FROM openplatform_v2_permission_p_t pp WHERE pp.parent_id = p.id AND pp.property_name = 'need_approval' AND pp.property_value = #{needApproval} )
ORDER BY p.create_time DESC LIMIT #{offset}, #{pageSize}

